.darma-loader-darma-custom-416 {--loader-bg: var(--loader-bg, #ffffff);
  --loader-secondary-color: var(--loader-secondary-color, #fb7185);
  width: 50px;
  aspect-ratio: 1;
  color: var(--loader-color, #e11d48);
  border: 2px solid;
  box-sizing: border-box;
  background:repeating-conic-gradient(#0000 0 90deg,currentColor 0 180deg),repeating-conic-gradient(currentColor 0 90deg,#0000 0 180deg);
  background-size: 16px 16px;
  background-position: 0 0;
  animation: darma-loader-darma-custom-416-l7 2s infinite;
}@keyframes darma-loader-darma-custom-416-l7{100% {background-position: 0px 32px,16px 0px}}

